import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';

const Home = () => {
  const [scrollY, setScrollY] = useState(0);
  const [activeQuote, setActiveQuote] = useState(0);

  useEffect(() => {
    const handleScroll = () => setScrollY(window.scrollY);
    window.addEventListener('scroll', handleScroll, { passive: true });
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  // Rotate quotes every 6 seconds
  const quotes = [
    { text: "Life is a journey. Enjoy the ride.", author: "— Unknown" },
    { text: "Four wheels move the body. Two wheels move the soul.", author: "— Anonymous" },
    { text: "The road is there, it will always be there. You just have to decide when to take it.", author: "— Chris Guillebeau" },
    { text: "Riding is not a hobby. It's a way of life.", author: "— BikesZone" },
  ];

  useEffect(() => {
    const interval = setInterval(() => {
      setActiveQuote((prev) => (prev + 1) % quotes.length);
    }, 6000);
    return () => clearInterval(interval);
  }, [quotes.length]);

  const specialties = [
    {
      icon: '🔒',
      title: 'Secure Bulk Transactions',
      desc: 'Every wholesale order is protected by end-to-end encrypted payments with escrow — so your money is safe until delivery is confirmed.',
    },
    {
      icon: '✅',
      title: 'Verified & Trusted Network',
      desc: 'We personally verify every manufacturer and dealer with KYC, audits, and quality checks. No fakes, no fraud — ever.',
    },
    {
      icon: '🏭',
      title: 'Direct from Manufacturers',
      desc: 'Cut the middlemen. Connect directly with OEMs like Bajaj, Royal Enfield, Yamaha, KTM, Honda — and get the best prices.',
    },
    {
      icon: '🚚',
      title: 'Pan-India Logistics',
      desc: 'Integrated logistics with real-time GPS tracking for every bulk shipment. From Kashmir to Kanyakumari — we deliver.',
    },
    {
      icon: '📊',
      title: 'Real-Time Market Intelligence',
      desc: 'Live pricing, demand trends, and competitor insights — make smarter trading decisions with data, not guesswork.',
    },
    {
      icon: '💎',
      title: 'Built for Scale',
      desc: 'Whether you trade 10 bikes or 10,000 — our platform handles MOQ, negotiation, invoicing, and analytics seamlessly.',
    },
  ];

  const stats = [
    { value: '2,500+', label: 'Bikes Listed', icon: '🏍️' },
    { value: '180+', label: 'Verified Dealers', icon: '🤝' },
    { value: '₹45Cr+', label: 'Trade Volume', icon: '💰' },
    { value: '5', label: 'Cities & Growing', icon: '🏙️' },
  ];

  return (
    <div className="landing-page">

      {/* ═══════ SECTION 1: FULL-SCREEN CINEMATIC HERO ═══════ */}
      <section className="landing-hero">
        <video
          className="landing-hero-video"
          autoPlay
          muted
          loop
          playsInline
          onLoadedData={(e) => { e.target.playbackRate = 0.65; }}
          src={`${process.env.PUBLIC_URL}/bikes/hero-video.mp4`}
        />
        <div className="landing-hero-overlay"></div>

        <div className="landing-hero-content">
          <div className="landing-hero-badge">
            <span className="landing-hero-badge-dot"></span>
            India's Premier B2B Bike Platform
          </div>

          <h1 className="landing-hero-title">
            Where <span>Dealers</span> Meet <span>Manufacturers</span>
          </h1>

          <p className="landing-hero-subtitle">
            The trusted marketplace for bulk motorcycle trading.
            Transparent pricing. Verified partners. Seamless logistics.
          </p>

          {/* Rotating Quote */}
          <div className="landing-quote-rotator">
            <p className="landing-quote-text" key={activeQuote}>
              "{quotes[activeQuote].text}"
            </p>
            <span className="landing-quote-author">{quotes[activeQuote].author}</span>
          </div>

          <div className="landing-hero-cta">
            <Link to="/inventory" className="btn btn-primary btn-lg landing-btn-glow">
              🏍️ Enter the Marketplace
            </Link>
            <Link to="/dealers" className="btn btn-white-outline btn-lg">
              📋 Register as Dealer
            </Link>
          </div>
        </div>

        {/* Scroll indicator */}
        <div className="landing-scroll-indicator">
          <span>Scroll to explore</span>
          <div className="landing-scroll-arrow">↓</div>
        </div>
      </section>

      {/* ═══════ SECTION 2: VISION QUOTE ═══════ */}
      <section className="landing-vision">
        <div className="landing-vision-inner">
          <div className="landing-vision-tag">Our Vision</div>
          <blockquote className="landing-vision-quote">
            "We believe every dealer deserves <em>direct access</em> to manufacturers,
            every manufacturer deserves <em>transparent demand</em>, and every
            transaction deserves <em>absolute trust</em>."
          </blockquote>
          <p className="landing-vision-desc">
            BikesZone was built to eliminate the chaos of traditional bike distribution.
            No more middlemen inflating prices. No more opaque deals. No more broken promises.
            Just a clean, powerful platform where serious traders do business — at scale.
          </p>
        </div>
      </section>

      {/* ═══════ SECTION 3: WHAT MAKES US SPECIAL ═══════ */}
      <section className="landing-specialties">
        <div className="section-header">
          <div className="section-tag">Why BikesZone</div>
          <h2 className="section-title">Built Different. Built to Last.</h2>
          <p className="section-desc">Six pillars that make BikesZone the most trusted B2B bike platform in India</p>
        </div>

        <div className="landing-specialties-grid">
          {specialties.map((s, i) => (
            <div className="landing-specialty-card" key={i}>
              <div className="landing-specialty-icon">{s.icon}</div>
              <h3 className="landing-specialty-title">{s.title}</h3>
              <p className="landing-specialty-desc">{s.desc}</p>
              <div className="landing-specialty-line"></div>
            </div>
          ))}
        </div>
      </section>

      {/* ═══════ SECTION 4: LIVING NUMBERS ═══════ */}
      <section className="landing-stats">
        <div className="landing-stats-inner">
          <div className="landing-stats-quote">
            <p>"The only impossible journey is the one you never begin."</p>
            <span>— Tony Robbins</span>
          </div>
          <div className="landing-stats-grid">
            {stats.map((s, i) => (
              <div className="landing-stat-item" key={i}>
                <div className="landing-stat-icon">{s.icon}</div>
                <div className="landing-stat-value">{s.value}</div>
                <div className="landing-stat-label">{s.label}</div>
              </div>
            ))}
          </div>
        </div>
      </section>

      {/* ═══════ SECTION 5: PEACEFUL CLOSING ═══════ */}
      <section className="landing-closing">
        <div className="landing-closing-inner">
          <div className="landing-closing-quote">
            "It's not about the destination. It's about the ride — and who rides with you."
          </div>
          <p className="landing-closing-sub">
            Join 180+ verified dealers and manufacturers building the future of motorcycle trade in India.
          </p>
          <div className="landing-closing-cta">
            <Link to="/inventory" className="btn btn-primary btn-lg landing-btn-glow">
              Start Trading Today →
            </Link>
          </div>
          <div className="landing-closing-peace">🏍️</div>
        </div>
      </section>
    </div>
  );
};

export default Home;
